const nome = tagMatch ? tagMatch[1].trim() : 'N/A';
const imovel = tagMatch ? tagMatch[2].trim() : 'N/A';
const codigo = tagMatch ? tagMatch[3].trim() : 'N/A';
// Remove a tag completa incluindo qualquer texto residual na mesma linha
const textoLimpo = output
  .replace(/\[NOTIFICAR_CORRETOR:[^\]]+\]/gi, '')
  .replace(/NOTIFICAR_CORRETOR:[^\n]*/gi, '')
  .replace(/\n{2,}/g, '\n')
  .trim();
